@code {
    private const int PageSize = 30;

    private List<Channel>? _channels;
    private int _activeChannelId;
    private Channel? _activeChannel;

    private List<Message>? _messages;
    private int _messageSkip;
    private bool _loadingMore;
    private bool _allMessagesLoaded;

    private bool _threadOpen;
    private int? _threadRootId;
    private Message? _threadRootMessage;
    private List<Message>? _threadReplies;

    private string _newMessage = string.Empty;
    private string _threadReplyText = string.Empty;

    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;

    private Dictionary<int, ThreadSummary> _threadSummaries = new();

    private ElementReference _messageListRef;

    private static readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannelAsync(_channels[0]);
        }
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        _activeChannelId = channel.Id;
        _activeChannel = channel;
        _messageSkip = 0;
        _allMessagesLoaded = false;
        _messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _messageSkip = _messages.Count;
        BuildThreadSummaries();
        await ChatService.MarkChannelReadAsync(channel.Id);
        _emojiPickerMessageId = null;

        // Refresh channel list to update unread counts
        _channels = await ChatService.GetChannelsAsync();

        await ScrollToBottom();
    }

    private async Task LoadOlderMessagesAsync()
    {
        if (_loadingMore || _allMessagesLoaded || _activeChannel is null)
            return;

        _loadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannel.Id, _messageSkip, PageSize);

        if (older.Count == 0)
        {
            _allMessagesLoaded = true;
        }
        else
        {
            _messages = [..older, ..(_messages ?? [])];
            _messageSkip += older.Count;
            BuildThreadSummaries();
        }

        _loadingMore = false;
    }

    private void BuildThreadSummaries()
    {
        if (_messages is null) return;

        _threadSummaries.Clear();
        var rootIds = _messages
            .Where(m => m.ReplyToId is null)
            .Select(m => m.Id)
            .ToHashSet();

        var replies = _messages.Where(m => m.ReplyToId is not null).ToList();

        foreach (var group in replies.GroupBy(m => m.ReplyToId!.Value))
        {
            if (rootIds.Contains(group.Key))
            {
                _threadSummaries[group.Key] = new ThreadSummary(
                    group.Key,
                    group.Count(),
                    group.Max(m => m.SentAt)
                );
            }
        }
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessage) || _activeChannel is null)
            return;

        var sent = await ChatService.SendMessageAsync(_activeChannel.Id, _newMessage.Trim(), null);
        _messages ??= [];
        _messages.Add(sent);
        _messageSkip++;
        _newMessage = string.Empty;

        await ScrollToBottom();
    }

    private async Task OnMessageKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendMessageAsync();
        }
    }

    private async Task OnMessageListScroll()
    {
        // JS interop to check scroll position
        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop < 50)
        {
            await LoadOlderMessagesAsync();
        }
    }

    private async Task OpenThreadAsync(int rootMessageId)
    {
        _threadRootId = rootMessageId;
        _threadOpen = true;
        _emojiPickerMessageId = null;

        _threadRootMessage = _messages?.FirstOrDefault(m => m.Id == rootMessageId);

        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);

        // Update thread summary with authoritative data
        if (_threadReplies.Count > 0)
        {
            _threadSummaries[rootMessageId] = new ThreadSummary(
                rootMessageId,
                _threadReplies.Count,
                _threadReplies.Max(r => r.SentAt)
            );
        }
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootId = null;
        _threadRootMessage = null;
        _threadReplies = null;
        _threadReplyText = string.Empty;
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_threadReplyText) || _threadRootId is null || _activeChannel is null)
            return;

        var reply = await ChatService.SendMessageAsync(_activeChannel.Id, _threadReplyText.Trim(), _threadRootId);
        _threadReplies ??= [];
        _threadReplies.Add(reply);
        _threadReplyText = string.Empty;

        // Update thread summary
        _threadSummaries[_threadRootId.Value] = new ThreadSummary(
            _threadRootId.Value,
            _threadReplies.Count,
            reply.SentAt
        );
    }

    private async Task OnThreadKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendThreadReplyAsync();
        }
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        _emojiPickerMessageId = null;

        // Refresh messages to reflect updated reactions
        if (_activeChannel is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_activeChannel.Id, 0, _messageSkip);
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task ScrollToBottom()
    {
        await Task.Yield();
        try
        {
            await JS.InvokeVoidAsync("eval",
                "document.querySelector('.message-list')?.scrollTo(0, document.querySelector('.message-list').scrollHeight)");
        }
        catch { /* element may not exist yet */ }
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string TruncateDescription(string desc)
    {
        return desc.Length <= 50 ? desc : desc[..47] + "…";
    }
}

