toolArgs.file_text:
/* ── Chat Container Layout ── */

.chat-container {
    display: flex;
    height: 100vh;
    width: 100vw;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    color: #1d1c1d;
    background: #fff;
}

/* ── Channel Sidebar ── */

.channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #3f0e40;
    color: #cfc3cf;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #522653;
}

.sidebar-header {
    padding: 16px 16px 8px;
    border-bottom: 1px solid #522653;
}

    .sidebar-header h3 {
        margin: 0;
        color: #fff;
        font-size: 1.1rem;
    }

.channel-list {
    list-style: none;
    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: 8px 16px;
    cursor: pointer;
    position: relative;
    transition: background 0.15s;
}

    .channel-item:hover {
        background: #4a154b;
    }

    .channel-item.active {
        background: #1164a3;
        color: #fff;
    }

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
}

.channel-desc {
    font-size: 0.75rem;
    opacity: 0.7;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    margin-top: 2px;
}

.unread-badge {
    position: absolute;
    right: 12px;
    top: 50%;
    transform: translateY(-50%);
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 2px 7px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

/* ── Main Message Area ── */

.message-area {
    width: 55%;
    display: flex;
    flex-direction: column;
    background: #fff;
    transition: width 0.2s ease;
}

    .message-area.expanded {
        width: 80%;
    }

.message-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e8e8e8;
    flex-shrink: 0;
}

    .message-header h2 {
        margin: 0;
        font-size: 1.15rem;
    }

.channel-description {
    font-size: 0.85rem;
    color: #616061;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 12px 20px;
}

.loading-indicator {
    text-align: center;
    color: #888;
    padding: 10px;
    font-size: 0.85rem;
}

.no-channel-selected {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #888;
    font-size: 1.1rem;
}

/* ── Message Bubble ── */

.message-bubble {
    position: relative;
    padding: 8px 12px;
    border-radius: 6px;
    margin-bottom: 4px;
    transition: background 0.1s;
}

    .message-bubble:hover {
        background: #f8f8f8;
    }

.message-meta {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.msg-author {
    font-size: 0.95rem;
}

.msg-time {
    font-size: 0.75rem;
    color: #999;
}

.msg-content {
    font-size: 0.93rem;
    line-height: 1.5;
    white-space: pre-wrap;
    word-break: break-word;
}

/* ── Reactions ── */

.reaction-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    background: #f0f0f0;
    border: 1px solid #ddd;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background 0.15s;
    line-height: 1.4;
}

    .reaction-badge:hover {
        background: #e0e0f8;
        border-color: #aaa;
    }

/* ── Thread link ── */

.thread-link {
    background: none;
    border: none;
    color: #1264a3;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 2px 0;
    margin-top: 2px;
    font-weight: 600;
}

    .thread-link:hover {
        text-decoration: underline;
    }

/* ── Hover Actions ── */

.message-actions {
    position: absolute;
    right: 8px;
    top: -10px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 2px 4px;
    box-shadow: 0 1px 4px rgba(0,0,0,0.1);
    z-index: 10;
}

.action-btn {
    background: none;
    border: none;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    white-space: nowrap;
}

    .action-btn:hover {
        background: #f0f0f0;
    }

/* ── Emoji Picker ── */

.emoji-picker-wrapper {
    position: relative;
}

.emoji-picker {
    position: absolute;
    right: 0;
    top: 100%;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    padding: 6px;
    display: flex;
    gap: 2px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.15);
    z-index: 20;
}

.emoji-option {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    line-height: 1;
}

    .emoji-option:hover {
        background: #f0f0f0;
    }

/* ── Message Input Area ── */

.message-input-area {
    display: flex;
    gap: 8px;
    padding: 12px 20px;
    border-top: 1px solid #e8e8e8;
    flex-shrink: 0;
    background: #fff;
}

    .message-input-area textarea {
        flex: 1;
        resize: none;
        border: 1px solid #ccc;
        border-radius: 6px;
        padding: 8px 12px;
        font-size: 0.9rem;
        font-family: inherit;
        outline: none;
        transition: border-color 0.15s;
    }

        .message-input-area textarea:focus {
            border-color: #1264a3;
        }

.send-btn {
    background: #007a5a;
    color: #fff;
    border: none;
    border-radius: 6px;
    padding: 8px 20px;
    font-size: 0.9rem;
    font-weight: 600;
    cursor: pointer;
    align-self: flex-end;
    transition: background 0.15s;
}

    .send-btn:hover:not(:disabled) {
        background: #006b4f;
    }

    .send-btn:disabled {
        background: #ccc;
        cursor: default;
    }

/* ── Thread Panel ── */

.thread-panel {
    width: 25%;
    min-width: 250px;
    border-left: 1px solid #e8e8e8;
    display: flex;
    flex-direction: column;
    background: #fff;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #e8e8e8;
    flex-shrink: 0;
}

    .thread-header h3 {
        margin: 0;
        font-size: 1.05rem;
    }

.close-btn {
    background: none;
    border: none;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    color: #666;
}

    .close-btn:hover {
        background: #f0f0f0;
        color: #333;
    }

.thread-root-quote {
    padding: 12px 16px;
    background: #f8f8f8;
    border-bottom: 1px solid #e8e8e8;
    flex-shrink: 0;
}

    .thread-root-quote p {
        margin: 6px 0 0;
        font-size: 0.9rem;
        line-height: 1.45;
    }

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 16px;
}

.thread-reply {
    padding: 6px 0;
}

